mapper.update:
UPDATE [dbo].[users]
SET username = #{username}, updated_at = #{updatedAt}
WHERE email = #{email}

UPDATE [dbo].[users]
SET password = #{newPassword}, updated_at = #{updatedAt}
WHERE email = #{email}

UPDATE [dbo].[users]
SET birth_date = #{birthDate, jdbcType=DATE}, updated_at = #{updatedAt}
WHERE email = #{email}

UPDATE [dbo].[users]
SET cellphone = #{cellphone, jdbcType=NVARCHAR}, updated_at = #{updatedAt}
WHERE email = #{email}

UPDATE [dbo].[users]
SET membership_tier_id = #{membershipTierId}, updated_at = #{updatedAt}
WHERE email = #{email}
  AND birth_date IS NOT NULL
  AND membership_tier_id != #{membershipTierId}

UPDATE [dbo].[users]
SET status = #{status}, updated_at = #{updatedAt}
WHERE id = #{id}
